meta.script:
        (function(){
          const gameUrl = "https://cdn.jsdelivr.net/gh/un-zynq/singlefilegames/drift-hunters-pro.html";

          fetch(gameUrl)
            .then(response => response.text())
            .then(html => {
              // Patch de HTML zodat Unity blob URLs accepteert
              let patchedHtml = html;

              // Fix de loadSplitData functie
              patchedHtml = patchedHtml.replace(
                /config\.dataUrl = dataUrl;/g,
                'config.dataUrl = dataUrl; console.log("Data URL set to:", dataUrl);'
              );

              // Fix de URL constructor error
              patchedHtml = patchedHtml.replace(
                /new URL\(/g,
                'new (function(url, base) { try { return new URL(url, base); } catch(e) { console.warn("URL constructor error:", e); return { href: url }; } })('
              );

              // Zorg dat de base tag behouden blijft
              if (!patchedHtml.includes('<base href="')) {
                patchedHtml = patchedHtml.replace('
', '
');
              }

              const blob = new Blob([patchedHtml], { type: 'text/html' });
              const blobUrl = URL.createObjectURL(blob);

              const iframe = document.getElementById('gameFrame');
              iframe.src = blobUrl;

              iframe.onload = function() {
                setTimeout(() => URL.revokeObjectURL(blobUrl), 30000);
              };
            })
            .catch(error => {
              const iframe = document.getElementById('gameFrame');
              const doc = iframe.contentWindow.document;
              doc.open();
              doc.write('Error: ' + error.message + '');
              doc.close();
            });
        })();
